import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import Navbar from '../shared/Navbar';
import Footer from '../shared/Footer';
import { useAuth } from '../hooks/useAuth';
import {
  getStats,
  getUsers,
  getAdminSpaces,
  getAdminBookings,
  getAdminTourBookings,
  updateUser,
  deleteUser,
  deleteSpace,
  updateBookingStatus,
  updateTourBookingStatus
} from '../services/adminService';

export default function AdminDashboard() {
  const { user } = useAuth();
  const [activeTab, setActiveTab] = useState('stats');
  const [stats, setStats] = useState(null);
  const [users, setUsers] = useState([]);
  const [spaces, setSpaces] = useState([]);
  const [bookings, setBookings] = useState([]);
  const [tourBookings, setTourBookings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    loadStats();
  }, []);

  useEffect(() => {
    if (activeTab === 'users') loadUsers();
    if (activeTab === 'spaces') loadSpaces();
    if (activeTab === 'bookings') loadBookings();
    if (activeTab === 'tours') loadTourBookings();
  }, [activeTab]);

  const loadStats = async () => {
    try {
      setLoading(true);
      const data = await getStats();
      setStats(data.stats);
    } catch (err) {
      setError(err.message || 'Failed to load statistics');
    } finally {
      setLoading(false);
    }
  };

  const loadUsers = async () => {
    try {
      const data = await getUsers();
      setUsers(data.users || []);
    } catch (err) {
      setError(err.message || 'Failed to load users');
    }
  };

  const loadSpaces = async () => {
    try {
      const data = await getAdminSpaces();
      setSpaces(data.spaces || []);
    } catch (err) {
      setError(err.message || 'Failed to load spaces');
    }
  };

  const loadBookings = async () => {
    try {
      const data = await getAdminBookings();
      setBookings(data.bookings || []);
    } catch (err) {
      setError(err.message || 'Failed to load bookings');
    }
  };

  const loadTourBookings = async () => {
    try {
      const data = await getAdminTourBookings();
      setTourBookings(data.tourBookings || []);
    } catch (err) {
      setError(err.message || 'Failed to load tour bookings');
    }
  };

  const handleUpdateUserRole = async (userId, newRole) => {
    try {
      await updateUser(userId, { role: newRole });
      await loadUsers();
    } catch (err) {
      alert(err.message || 'Failed to update user role');
    }
  };

  const handleDeleteUser = async (userId) => {
    if (!window.confirm('Are you sure you want to delete this user?')) return;
    try {
      await deleteUser(userId);
      await loadUsers();
    } catch (err) {
      alert(err.message || 'Failed to delete user');
    }
  };

  const handleDeleteSpace = async (spaceId) => {
    if (!window.confirm('Are you sure you want to delete this space?')) return;
    try {
      await deleteSpace(spaceId);
      await loadSpaces();
    } catch (err) {
      alert(err.message || 'Failed to delete space');
    }
  };

  const handleUpdateBookingStatus = async (bookingId, status) => {
    try {
      await updateBookingStatus(bookingId, status);
      await loadBookings();
    } catch (err) {
      alert(err.message || 'Failed to update booking status');
    }
  };

  const handleUpdateTourStatus = async (tourId, status) => {
    try {
      await updateTourBookingStatus(tourId, status);
      await loadTourBookings();
    } catch (err) {
      alert(err.message || 'Failed to update tour status');
    }
  };

  if (loading && !stats) {
    return (
      <div className="min-h-screen flex flex-col bg-white">
        <Navbar />
        <main className="flex-1 flex items-center justify-center">
          <div className="text-center">
            <svg className="animate-spin h-12 w-12 text-sky-600 mx-auto" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
              <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
              <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
            </svg>
            <p className="mt-4 text-gray-600">Loading admin dashboard...</p>
          </div>
        </main>
        <Footer />
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col bg-white">
      <Navbar />
      <main className="flex-1 max-w-7xl mx-auto w-full px-6 md:px-12 lg:px-16 py-10">
        <div className="mb-8">
          <h1 className="text-3xl md:text-4xl font-extrabold tracking-tight text-gray-900">
            Admin Dashboard
          </h1>
          <p className="text-gray-600 mt-2">Manage users, spaces, bookings, and platform statistics</p>
        </div>

        {error && (
          <div className="mb-6 p-4 bg-red-50 border border-red-200 rounded-lg text-red-700">
            {error}
          </div>
        )}

        {/* Tabs */}
        <div className="mb-6 border-b border-gray-200">
          <nav className="-mb-px flex space-x-8">
            {['stats', 'users', 'spaces', 'bookings', 'tours'].map((tab) => (
              <button
                key={tab}
                onClick={() => setActiveTab(tab)}
                className={`py-4 px-1 border-b-2 font-medium text-sm capitalize ${
                  activeTab === tab
                    ? 'border-sky-500 text-sky-600'
                    : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
                }`}
              >
                {tab === 'tours' ? 'Tour Bookings' : tab}
              </button>
            ))}
          </nav>
        </div>

        {/* Stats Tab */}
        {activeTab === 'stats' && stats && (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            <div className="p-6 rounded-2xl border border-gray-100 shadow-sm bg-gradient-to-br from-blue-50 to-indigo-50">
              <div className="text-sm text-gray-600 mb-1">Total Users</div>
              <div className="text-3xl font-bold text-gray-900">{stats.totalUsers}</div>
              <div className="text-xs text-gray-500 mt-2">Workspace Owners: {stats.workspaceOwners}</div>
            </div>
            <div className="p-6 rounded-2xl border border-gray-100 shadow-sm bg-gradient-to-br from-emerald-50 to-green-50">
              <div className="text-sm text-gray-600 mb-1">Total Spaces</div>
              <div className="text-3xl font-bold text-gray-900">{stats.totalSpaces}</div>
            </div>
            <div className="p-6 rounded-2xl border border-gray-100 shadow-sm bg-gradient-to-br from-amber-50 to-orange-50">
              <div className="text-sm text-gray-600 mb-1">Total Bookings</div>
              <div className="text-3xl font-bold text-gray-900">{stats.totalBookings}</div>
              <div className="text-xs text-gray-500 mt-2">Active: {stats.activeBookings} | Pending: {stats.pendingBookings}</div>
            </div>
            <div className="p-6 rounded-2xl border border-gray-100 shadow-sm bg-gradient-to-br from-purple-50 to-pink-50">
              <div className="text-sm text-gray-600 mb-1">Total Revenue</div>
              <div className="text-3xl font-bold text-gray-900">₹{stats.totalRevenue?.toLocaleString() || 0}</div>
              <div className="text-xs text-gray-500 mt-2">Recent (7d): {stats.recentBookings}</div>
            </div>
          </div>
        )}

        {/* Users Tab */}
        {activeTab === 'users' && (
          <div className="bg-white rounded-2xl border border-gray-100 shadow-sm overflow-hidden">
            <div className="overflow-x-auto">
              <table className="min-w-full divide-y divide-gray-200">
                <thead className="bg-gray-50">
                  <tr>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Name</th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Email</th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Role</th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Actions</th>
                  </tr>
                </thead>
                <tbody className="bg-white divide-y divide-gray-200">
                  {users.map((u) => (
                    <tr key={u._id}>
                      <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">{u.fullName}</td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{u.email}</td>
                      <td className="px-6 py-4 whitespace-nowrap">
                        <select
                          value={u.role}
                          onChange={(e) => handleUpdateUserRole(u._id, e.target.value)}
                          className="text-sm border-gray-300 rounded-md focus:ring-sky-500 focus:border-sky-500"
                        >
                          <option value="user">User</option>
                          <option value="workspace_owner">Workspace Owner</option>
                          <option value="admin">Admin</option>
                        </select>
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm">
                        <button
                          onClick={() => handleDeleteUser(u._id)}
                          className="text-red-600 hover:text-red-900"
                          disabled={u._id === user?._id}
                        >
                          Delete
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {/* Spaces Tab */}
        {activeTab === 'spaces' && (
          <div className="space-y-4">
            {spaces.map((space) => (
              <div key={space._id} className="p-6 rounded-2xl border border-gray-100 shadow-sm bg-white">
                <div className="flex items-start justify-between">
                  <div className="flex-1">
                    <h3 className="text-lg font-bold text-gray-900">{space.name}</h3>
                    <p className="text-sm text-gray-600 mt-1">{space.city} • {space.type}</p>
                    <p className="text-sm font-semibold text-gray-900 mt-2">₹{space.pricePerDay}/day</p>
                  </div>
                  <button
                    onClick={() => handleDeleteSpace(space._id)}
                    className="ml-4 px-4 py-2 text-sm text-red-600 hover:text-red-900 border border-red-200 rounded-lg hover:bg-red-50"
                  >
                    Delete
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}

        {/* Bookings Tab */}
        {activeTab === 'bookings' && (
          <div className="space-y-4">
            {bookings.map((booking) => (
              <div key={booking._id} className="p-6 rounded-2xl border border-gray-100 shadow-sm bg-white">
                <div className="flex items-start justify-between">
                  <div className="flex-1">
                    <h3 className="text-lg font-bold text-gray-900">{booking.spaceName}</h3>
                    <p className="text-sm text-gray-600 mt-1">
                      User: {booking.user?.fullName || booking.user?.email} • {new Date(booking.bookingDate).toLocaleDateString()}
                    </p>
                    <p className="text-sm font-semibold text-gray-900 mt-2">₹{booking.totalAmount}</p>
                    <span className={`inline-block mt-2 px-2 py-1 rounded text-xs font-semibold ${
                      booking.status === 'confirmed' ? 'bg-emerald-100 text-emerald-700' :
                      booking.status === 'pending' ? 'bg-amber-100 text-amber-700' :
                      'bg-gray-100 text-gray-700'
                    }`}>
                      {booking.status}
                    </span>
                  </div>
                  <select
                    value={booking.status}
                    onChange={(e) => handleUpdateBookingStatus(booking._id, e.target.value)}
                    className="ml-4 text-sm border-gray-300 rounded-md focus:ring-sky-500 focus:border-sky-500"
                  >
                    <option value="pending">Pending</option>
                    <option value="confirmed">Confirmed</option>
                    <option value="cancelled">Cancelled</option>
                    <option value="completed">Completed</option>
                  </select>
                </div>
              </div>
            ))}
          </div>
        )}

        {/* Tour Bookings Tab */}
        {activeTab === 'tours' && (
          <div className="space-y-4">
            {tourBookings.map((tour) => (
              <div key={tour._id} className="p-6 rounded-2xl border border-gray-100 shadow-sm bg-white">
                <div className="flex items-start justify-between">
                  <div className="flex-1">
                    <h3 className="text-lg font-bold text-gray-900">{tour.spaceName}</h3>
                    <p className="text-sm text-gray-600 mt-1">
                      {tour.contactName} ({tour.contactEmail}) • {new Date(tour.tourDate).toLocaleDateString()} at {tour.tourTime}
                    </p>
                    <span className={`inline-block mt-2 px-2 py-1 rounded text-xs font-semibold ${
                      tour.status === 'confirmed' ? 'bg-emerald-100 text-emerald-700' :
                      tour.status === 'pending' ? 'bg-amber-100 text-amber-700' :
                      'bg-gray-100 text-gray-700'
                    }`}>
                      {tour.status}
                    </span>
                  </div>
                  <select
                    value={tour.status}
                    onChange={(e) => handleUpdateTourStatus(tour._id, e.target.value)}
                    className="ml-4 text-sm border-gray-300 rounded-md focus:ring-sky-500 focus:border-sky-500"
                  >
                    <option value="pending">Pending</option>
                    <option value="confirmed">Confirmed</option>
                    <option value="cancelled">Cancelled</option>
                    <option value="completed">Completed</option>
                  </select>
                </div>
              </div>
            ))}
          </div>
        )}
      </main>
      <Footer />
    </div>
  );
}
